                "heading": "Code Example",
                "code": "@RestController @RequestMapping(\"/api/v1/students\") @RequiredArgsConstructor\npublic class StudentController {\n    private final StudentService svc;\n\n    @GetMapping public ResponseEntity<List<StudentDTO>> getAll() {\n        return ResponseEntity.ok(svc.getAll());\n    }\n    @GetMapping(\"/{id}\") public ResponseEntity<StudentDTO> getById(@PathVariable Long id) {\n        return ResponseEntity.ok(svc.findById(id));\n    }\n    @PostMapping public ResponseEntity<StudentDTO> create(@Valid @RequestBody CreateStudentReq req) {\n        StudentDTO dto = svc.create(req);\n        return ResponseEntity.created(URI.create(\"/api/v1/students/\"+dto.getId())).body(dto);\n    }\n    @PutMapping(\"/{id}\") public ResponseEntity<StudentDTO> update(\n            @PathVariable Long id, @Valid @RequestBody UpdateStudentReq req) {\n        return ResponseEntity.ok(svc.update(id,req));\n    }\n    @DeleteMapping(\"/{id}\") public ResponseEntity<Void> delete(@PathVariable Long id) {\n        svc.delete(id); return ResponseEntity.noContent().build();\n    }\n}"
